use cardano/transaction.{Transaction, InlineDatum}
use aiken/collection/list
use aiken/interval

pub type DeadlineDatum {
  expiry: Int,
}

validator deadline_check {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let expiry =
      list.foldr(
        self.reference_inputs,
        None,
        fn(input, acc) {
          when input.output.datum is {
            InlineDatum(raw) ->
              when raw is {
                d: DeadlineDatum -> Some(d.expiry)
                _ -> acc
              }
            _ -> acc
          }
        },
      )
    when expiry is {
      Some(e) -> interval.is_entirely_before(self.validity_range, e)
      None -> False
    }
  }
}

