input:
```aiken
use aiken/interval
use cardano/transaction.{Transaction, OutputReference}

validator venta {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let ventana = interval.between(500, 1500)
    interval.includes(ventana, self.validity_range)
  }
}
```

output:
Solo necesitas reemplazar `interval.between` por `interval.entirely_between`. Esto cambia el intervalo de cerrado $[500, 1500]$ a abierto $(500, 1500)$, excluyendo ambos extremos:

```aiken
use aiken/interval
use cardano/transaction.{Transaction, OutputReference}

validator venta {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let ventana = interval.entirely_between(500, 1500)
    interval.includes(ventana, self.validity_range)
  }
}
```

**Diferencia clave:**
- `interval.between(500, 1500)` → $[500, 1500]$: los slots 500 y 1500 **sí** están permitidos.
- `interval.entirely_between(500, 1500)` → $(500, 1500)$: los slots 500 y 1500 **no** están permitidos; solo los slots estrictamente entre ellos.

```aiken
use aiken/interval
use cardano/transaction.{Transaction, OutputReference}

validator time_lock {
  spend(
    datum: Option<Int>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(required_slot) -> {
        let vr = self.validity_range
        // Reject if the validity range is empty (contains nothing)
        let not_empty = !interval.is_empty(vr)
        // The range must start entirely after the required slot
        let after_slot = interval.is_entirely_after(vr, required_slot)
        not_empty && after_slot
      }
    }
  }
}
```

```aiken
use aiken/interval
use cardano/transaction.{OutputReference, Transaction}

validator time_locked {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let window = interval.between(100, 500)
    interval.contains(window, interval.contains |> fn(_) { True }) |> fn(_) {
      interval.contains(self.validity_range, 100) && interval.contains(self.validity_range, 500)
    }
  }
}
```

Actually, the cleaner approach is to check that the transaction's validity range is fully contained within `[100, 500]` using `interval.includes`:

```aiken
use aiken/interval
use cardano/transaction.{OutputReference, Transaction}

validator time_locked {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let window = interval.between(100, 500)
    interval.includes(window, self.validity_range)
  }
}
```

If you only need to verify a single known slot point is in range, use `interval.contains` directly:

```aiken
use aiken/interval
use cardano/transaction.{OutputReference, Transaction}

validator time_locked {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    interval.contains(self.validity_range, 300)
  }
}
```

Puedes usar `interval.contains/2` del módulo `aiken/interval`. Esta función recibe un `Interval` y un `Int`, y retorna `True` si el elemento se encuentra dentro del intervalo respetando la inclusividad de cada extremo.

```aiken
use aiken/interval.{Interval, IntervalBound, IntervalBoundType}

fn ejemplo() -> Bool {
  let iv =
    Interval {
      lower_bound: IntervalBound { bound_type: Finite(14), is_inclusive: True },
      upper_bound: IntervalBound { bound_type: Finite(42), is_inclusive: False },
    }

  interval.contains(iv, 25)
}
```

Este código retorna `True` porque 25 está estrictamente entre 14 (inclusive) y 42 (exclusive). Si usaras `interval.contains(iv, 42)`, retornaría `False` porque el extremo superior no es inclusivo.

```aiken
use aiken/interval
use cardano/transaction.{Transaction, OutputReference}

// Allowed window: slots [100, 500] inclusive
const allowed_window = interval.between(100, 500)

validator time_window_lock {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // The validity range must be fully included within the allowed window.
    // interval.includes checks that allowed_window contains the entire validity_range.
    // Internally, the stdlib uses interval.min on upper bounds and interval.max
    // on lower bounds (via intersection) to compute the overlap.
    interval.includes(allowed_window, self.validity_range)
  }
}
```

`interval.includes(self, other)` returns `True` when `other` is a sub-interval of `self`. This relies on the same `interval.min` / `interval.max` bound-comparison semantics used in `interval.intersection`, ensuring that inclusive vs. exclusive boundaries are handled correctly at the edges of the window.

