    _datum: Option<Void>,
    redeemer: Int,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    // A positive integer x is a power of 2 iff 2^(log2(x)) == x
    let k = math.log2(redeemer)
    math.pow2(k) == redeemer
  }
}
```

`math.log2` gives the floor exponent; raising 2 to that exponent and comparing with the original value confirms it is an exact power of 2.

