```aiken
use aiken/interval.{Interval, IntervalBound}
use cardano/transaction.{ValidityRange}

pub type NormalizedTimeRange {
  ClosedRange { lower: Int, upper: Int }
  FromNegInf { upper: Int }
  ToPosInf { lower: Int }
  Always
  InvalidRange
}

pub fn normalize_time_range(
  validity_range: ValidityRange,
) -> NormalizedTimeRange {
  let Interval {
    lower_bound: IntervalBound {
      bound_type: lower_bound_type,
      is_inclusive: lower_is_inclusive,
    },
    upper_bound: IntervalBound {
      bound_type: upper_bound_type,
      is_inclusive: upper_is_inclusive,
    },
  } = validity_range
  when (lower_bound_type, upper_bound_type) is {
    (interval.NegativeInfinity, interval.PositiveInfinity) -> Always
    (interval.NegativeInfinity, interval.Finite(upper_int)) ->
      FromNegInf { upper: resolve_upper(upper_int, upper_is_inclusive) }
    (interval.Finite(init_lower_int), interval.Finite(init_upper_int)) -> {
      let lower = resolve_lower(init_lower_int, lower_is_inclusive)
      let upper = resolve_upper(init_upper_int, upper_is_inclusive)
      if lower >= upper {
        InvalidRange
      } else {
        ClosedRange { lower, upper }
      }
    }
    (interval.Finite(init_lower_int), interval.PositiveInfinity) ->
      ToPosInf { lower: resolve_lower(init_lower_int, lower_is_inclusive) }
    _ -> InvalidRange
  }
}

fn resolve_lower(init_lower: Int, is_inclusive: Bool) -> Int {
  if is_inclusive {
    init_lower
  } else {
    init_lower + 1
  }
}

fn resolve_upper(init_upper: Int, is_inclusive: Bool) -> Int {
  if is_inclusive {
    init_upper
  } else {
    init_upper - 1
  }
}
```

The key insight is that `resolve_lower` shifts an exclusive lower bound up by 1, and `resolve_upper` shifts an exclusive upper bound down by 1, so the resulting integers are always in inclusive form.

According to the EUTxO crash course, a transaction output must have at least two fields:

1. **Address** – describes the conditions needed to use (spend) the value associated with the output.
2. **Value** – the assets locked at that address.

In Aiken's `cardano/transaction` module, the `Output` type represents this structure. You can inspect the value of an output using helpers from `cardano/assets`, for example:

```aiken
use cardano/assets
use cardano/transaction.{Output}

