    redeemer: MintRedeemer,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let has_authorized_signer =
      list.any(
        redeemer.authorized_signers,
        fn(signer) { list.has(self.extra_signatories, signer) },
      )

    let minted_quantity =
      assets.quantity_of(self.mint, policy_id, redeemer.asset_name)

    has_authorized_signer && minted_quantity == 1
  }
}
```

**Explicación:**
- El redeemer transporta la lista de signatarios autorizados y el nombre del asset a acuñar.
- `list.any/2` verifica que al menos uno de los signatarios autorizados esté presente en `self.extra_signatories`, que son los firmantes reales de la transacción enviada via CIP-0030.
- `assets.quantity_of/3` confirma que solo se acuña exactamente 1 unidad del NFT bajo esta política.
- Este patrón refleja la autorización que otorga la billetera del usuario a través del bridge CIP-0030: la dApp solicita la firma y el validador on-chain la verifica.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

validator smart_nft_policy(authority: VerificationKeyHash) {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    // Enforce authority signature
    let signed_by_authority =
      list.has(self.extra_signatories, authority)

    // Enforce that every minted token under this policy has quantity exactly 1
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let all_single_quantity =
      minted_tokens
        |> assets.to_dict
        // tokens() returns a Dict<AssetName, Int>; flatten to check quantities
        |> fn(d) {
             assets.flatten(assets.restricted_to(self.mint, [policy_id]))
           }
        |> list.all(fn(triple) {
             let (_, _, qty) = triple
             qty == 1
           })

    signed_by_authority && all_single_quantity
  }

  else(_) {
    fail
  }
}
```

**Key points aligned with CIP-0054:**
- Each Smart NFT is a unique token (quantity = 1), matching the NFT standard.
- The authority key check prevents unauthorised minting.
- `assets.flatten` gives `List<(PolicyId, AssetName, Int)>` so quantity checking is straightforward.
- `assets.restricted_to(self.mint, [policy_id])` isolates only tokens for this policy.

