validator token_price_feed_spend {
  fn spend(
    _datum: Option<Void>,
    redeemer: TokenBuyRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(feed_input) =
      transaction.find_input(self.reference_inputs, redeemer.feed_ref)
    expect InlineDatum(raw) = feed_input.output.datum
    expect feed: TokenFeed = raw
    let cost = redeemer.token_quantity * feed.price_per_token
    let buyer_gets_tokens =
      list.any(
        self.outputs,
        fn(o) {
          o.address.payment_credential == redeemer.buyer
            && assets.quantity_of(
                o.value,
                feed.token_policy,
                feed.token_name,
              ) >= redeemer.token_quantity
        },
      )
    let payment_made =
      list.any(
        self.inputs,
        fn(i) { assets.lovelace_of(i.output.value) >= cost },
      )
    buyer_gets_tokens && payment_made
  }
}

