  fn mint(
    redeemer: MintBurnRedeemer,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    when redeemer is {
      Mint { asset_name, quantity, authority } -> {
        let actual = assets.quantity_of(self.mint, policy_id, asset_name)
        actual == quantity && quantity > 0 && list.has(
          self.extra_signatories,
          authority,
        )
      }
      Burn { asset_name, burn_quantity } -> {
        let actual = assets.quantity_of(self.mint, policy_id, asset_name)
        actual == -burn_quantity && burn_quantity > 0
      }
    }
  }
}

