  quantity: Int,
  price_per_unit: Int,
  treasury_address: Address,
}

validator priced_mint {
  fn mint(
    redeemer: PricedMintRedeemer,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let PricedMintRedeemer {
      asset_name,
      quantity,
      price_per_unit,
      treasury_address,
    } = redeemer
    let actual = assets.quantity_of(self.mint, policy_id, asset_name)
    let required_ada = quantity * price_per_unit
    let treasury_paid =
      list.any(
        self.outputs,
        fn(output) {
          output.address == treasury_address && assets.lovelace_of(
            output.value,
          ) >= required_ada
        },
      )
    actual == quantity && quantity > 0 && treasury_paid
  }
}

