pub type TriPhaseDatum {
  owner: VerificationKeyHash,
  phase_a_start: Int,
  phase_a_end: Int,
  phase_b_start: Int,
  phase_b_end: Int,
  phase_c_start: Int,
  phase_c_end: Int,
}

validator triple_phase_token_unlock {
  fn spend(
    datum: Option<TriPhaseDatum>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let phase_a = interval.between(d.phase_a_start, d.phase_a_end)
        let phase_b = interval.between(d.phase_b_start, d.phase_b_end)
        let phase_c = interval.between(d.phase_c_start, d.phase_c_end)
        let ab_hull = interval.hull(phase_a, phase_b)
        let total_schedule = interval.hull(ab_hull, phase_c)
        let in_schedule = interval.includes(total_schedule, self.validity_range)
        let in_phase_a = interval.includes(phase_a, self.validity_range)
        let in_phase_b = interval.includes(phase_b, self.validity_range)
        let in_phase_c = interval.includes(phase_c, self.validity_range)
        let in_any_phase = in_phase_a || in_phase_b || in_phase_c
        let signed = list.has(self.extra_signatories, d.owner)
        in_schedule && in_any_phase && signed
      }
    }
  }
}

