use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets
use cardano/transaction.{Input, Output, OutputReference, Transaction}

pub type Datum {
  owner: VerificationKeyHash,
}

pub type Redeemer {
  input_index: Int,
  output_index: Int,
}

fn one_to_one(
  input_index: Int,
  output_index: Int,
  own_ref: OutputReference,
  inputs: List<Input>,
  outputs: List<Output>,
  double_satisfaction_prevented: Bool,
  validation_logic: fn(Input, Output) -> Bool,
) -> Bool {
  expect double_satisfaction_prevented
  expect Some(Input { output_reference: in_ref, .. } as in_input) =
    inputs |> list.at(input_index)
  expect Some(out_utxo) = outputs |> list.at(output_index)
  expect own_ref == in_ref
  validation_logic(in_input, out_utxo)
}

validator return_to_owner {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    one_to_one(
      redeemer.input_index,
      redeemer.output_index,
      own_ref,
      self.inputs,
      self.outputs,
      True,
      fn(_in_input, out_utxo) {
        list.has(self.extra_signatories, d.owner)
      },
    )
  }
}
```

