use cardano/transaction.{Transaction}

validator guardrails {
  propose(redeemer: Void, _index: Int, self: Transaction) -> Bool {
    list.length(self.proposal_procedures) > 0
  }
}
```

This guardrails validator ensures that any transaction invoking the `propose` script purpose actually contains at least one proposal procedure. The `propose` handler receives:
- `redeemer`: the script redeemer (here `Void`)
- `_index`: the 0-based index of the `ProposalProcedure` in `proposal_procedures`
- `self`: the full `Transaction`

Since `self.proposal_procedures` is a `List<ProposalProcedure>`, `list.length` checks it is non-empty.

```aiken
use cardano/assets
use cardano/transaction.{Transaction, OutputReference, find_input}

validator min_ada_lock {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when find_input(self.inputs, own_ref) is {
      Some(input) ->
        assets.lovelace_of(input.output.value) >= 5_000_000
      None -> False
    }
  }
}
```

**Explanation:**
- `find_input(self.inputs, own_ref)` searches the transaction inputs for the one matching `own_ref` (the script's own `OutputReference`), returning `Option<Input>`.
- `input.output.value` is the `Value` held at that UTxO.
- `assets.lovelace_of(...)` extracts the lovelace amount as an `Int`.
- If the input is not found (which should never happen in a well-formed transaction), the validator safely returns `False`.

```aiken
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}
use aiken/collection/list

validator single_asset_policy {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let minted_tokens =
      self.mint
        |> assets.tokens(policy_id)

    let asset_names =
      minted_tokens
        |> assets.flatten
        |> list.map(fn(triple) { let (_, name, _) = triple; name })
        |> list.unique

    list.length(asset_names) == 1
  }
}
```

This extracts all asset names minted under `policy_id`, deduplicates them with `list.unique`, and asserts there is exactly one unique name.

Puedes extraer todas las políticas de los valores de los inputs y luego usar `list.unique` para deduplicarlas. Si la longitud es igual, todas las políticas son únicas.

```aiken
use cardano/assets
use cardano/transaction.{Transaction, Input}
use aiken/collection/list

fn unique_input_policies(inputs: List<Input>) -> Bool {
  let all_policies =
    inputs
      |> list.flat_map(
          fn(input) { assets.policies(input.output.value) },
        )

  list.length(all_policies) == list.length(list.unique(all_policies))
}

validator check_unique_policies {
  spend(
    datum: Option<Void>,
    redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    unique_input_policies(self.inputs)
  }
}
```

`list.flat_map` aplana las listas de políticas de cada input en una sola lista, y `list.unique` elimina los duplicados para la comparación.

```aiken
use cardano/transaction.{OutputReference, Transaction, ScriptPurpose, Withdraw}
use cardano/credential.{ScriptCredential}
use aiken/collection/list

validator forwarding_spend(withdrawal_script_hash: ByteArray) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let target_credential = ScriptCredential(withdrawal_script_hash)
    list.any(
      self.redeemers,
      fn(pair) {
        when pair.1st is {
          Withdraw(cred) -> cred == target_credential
          _ -> False
        }
      },
    )
  }

  else(_) {
    fail
  }
}
```

## CIP-0054 Renderer Pattern

The `uses.renderer` field in CIP-0054 metadata allows many NFTs to point to a **single token that holds the rendering code**. Instead of embedding the same Javascript renderer in every NFT's metadata, each NFT stores only its input variables and declares which renderer to use. This massively reduces on-chain storage and duplication.

## Aiken Validator

To enforce that the renderer token is present as a reference input at spend time:

```aiken
use cardano/assets
use cardano/transaction.{Transaction, Input, OutputReference}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

validator smart_nft_renderer_check(
  renderer_policy: ByteArray,
  renderer_name: ByteArray,
) {
  spend(
    datum: Option<VerificationKeyHash>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Check renderer token is present in reference inputs
    let renderer_present =
      list.any(
        self.reference_inputs,
        fn(input: Input) {
          assets.quantity_of(
            input.output.value,
            renderer_policy,
            renderer_name,
          ) >= 1
        },
      )

    // Check owner signed (datum holds owner vkh)
    let owner_ok =
      when datum is {
        None -> False
        Some(owner) -> list.has(self.extra_signatories, owner)
      }

    renderer_present && owner_ok
  }

  else(_) {
    fail
  }
}
```

**Design notes:**
- `self.reference_inputs` lets the transaction include the renderer UTXO **without consuming it**, preserving it for all NFTs that reference it.
- `assets.quantity_of(input.output.value, ...)` checks the renderer token is in that reference input.
- `input.output.value` access is marked `PLAUSIBLE_NEEDS_CHECK` as nested field access on `Input.output` is not explicitly listed in the verified stdlib signatures.

```aiken
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Output, OutputReference, Transaction}

validator versioned_format_guard {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let has_approver =
      !list.is_empty(self.extra_signatories)

    let migration_fee = 2_000_000

    let has_migration_output =
      list.any(
        self.outputs,
        fn(output: Output) -> Bool {
          assets.lovelace_of(output.value) >= migration_fee
        },
      )

    has_approver && has_migration_output
  }

  else(_) {
    fail
  }
}
```

```aiken
use aiken/crypto
use cardano/transaction.{OutputReference, Transaction}

pub type Datum {
  expected_hash: ByteArray
}

pub type Redeemer {
  preimage: ByteArray
}

validator keccak_hashlock {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) -> {
        let computed = crypto.keccak_256(redeemer.preimage)
        computed == d.expected_hash
      }
      None -> False
    }
  }
}
```

This validator computes `keccak_256` over the redeemer's preimage and checks it matches the hash committed in the datum. This pattern mirrors Ethereum hash-lock contracts that use `keccak256` for trustless atomic swaps or payment channels.

```aiken
use aiken/builtin
use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

pub type AuctionDatum {
  seller_vk: ByteArray,
  auction_id: ByteArray,
}

pub type BidRedeemer {
  bid_price: Int,
  bidder_pkh: ByteArray,
  bidder_signature: ByteArray,
}

fn bidder_signature_message(
  auction_id: ByteArray,
  bid_price: Int,
  bidder_pkh: ByteArray,
) -> ByteArray {
  let price_bytes = builtin.integer_to_bytearray(True, 0, bid_price)
  builtin.append_bytearray(
    auction_id,
    builtin.append_bytearray(price_bytes, bidder_pkh),
  )
}

validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: BidRedeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let msg =
          bidder_signature_message(
            d.auction_id,
            redeemer.bid_price,
            redeemer.bidder_pkh,
          )
        builtin.verify_ed25519_signature(
          d.seller_vk,
          msg,
          redeemer.bidder_signature,
        )
      }
    }
  }
}
```

use aiken/collection/list
use cardano/address
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}

type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

type OwnerDatum {
  owner: VerificationKeyHash,
  locked_lovelace: Int,
}

validator owner_withdrawal {
  fn spend(
    datum: Option<OwnerDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let owner_signed = list.has(self.extra_signatories, d.owner)
    let owner_address = address.from_verification_key(d.owner)
    let sufficient_output =
      list.any(
        self.outputs,
        fn(o) {
          o.address == owner_address && assets.lovelace_of(o.value) >= d.locked_lovelace
        },
      )
    owner_signed && sufficient_output
  }
}

