type SplitDatum {
  admin: VerificationKeyHash,
  beneficiary_a: VerificationKeyHash,
  beneficiary_b: VerificationKeyHash,
  amount_a: Int,
  amount_b: Int,
}

validator split_payment {
  fn spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let admin_signed = list.has(self.extra_signatories, d.admin)
    let addr_a = address.from_verification_key(d.beneficiary_a)
    let addr_b = address.from_verification_key(d.beneficiary_b)
    let a_paid =
      list.any(
        self.outputs,
        fn(o) { o.address == addr_a && assets.lovelace_of(o.value) >= d.amount_a },
      )
    let b_paid =
      list.any(
        self.outputs,
        fn(o) { o.address == addr_b && assets.lovelace_of(o.value) >= d.amount_b },
      )
    admin_signed && a_paid && b_paid
  }
}

