    expect Some(d) = datum
    let seller_addr = address.from_verification_key(d.seller)
    let c1_addr = address.from_verification_key(d.creator1)
    let c2_addr = address.from_verification_key(d.creator2)
    let seller_ok =
      list.any(
        self.outputs,
        fn(o) {
          o.address == seller_addr && assets.lovelace_of(o.value) >= d.price
        },
      )
    let c1_ok =
      list.any(
        self.outputs,
        fn(o) {
          o.address == c1_addr && assets.lovelace_of(o.value) >= d.share1
        },
      )
    let c2_ok =
      list.any(
        self.outputs,
        fn(o) {
          o.address == c2_addr && assets.lovelace_of(o.value) >= d.share2
        },
      )
    seller_ok && c1_ok && c2_ok
  }
}

