}

validator precio_con_expiracion {
  fn spend(
    datum: Option<DatumConExpiracion>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let addr_vendedor = address.from_verification_key(d.vendedor)
    let antes_de_expiracion =
      interval.is_entirely_before(self.validity_range, d.expiracion)
    let pago_ok =
      list.any(
        self.outputs,
        fn(o) {
          o.address == addr_vendedor
            && assets.lovelace_of(o.value) >= d.precio_minimo
        },
      )
    antes_de_expiracion && pago_ok
  }
}

