use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction, find_input}

pub type AdminConfigDatum {
  admin_key: ByteArray
}

pub type SpendDatum {
  config_ref: OutputReference
}

validator admin_key_config_spend {
  fn spend(
    datum: Option<SpendDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(config_input) =
      find_input(self.reference_inputs, d.config_ref)
    expect InlineDatum(raw) = config_input.output.datum
    expect config: AdminConfigDatum = raw
    list.has(self.extra_signatories, config.admin_key)
  }
}

