  blacklist_ref: OutputReference
  firmante: ByteArray
}

validator gasto_con_lista_negra {
  fn spend(
    datum: Option<DatoGasto>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(ref_input) =
      find_input(self.reference_inputs, d.blacklist_ref)
    expect InlineDatum(raw) = ref_input.output.datum
    expect blacklist: BlacklistDatum = raw
    let firmante_bloqueado =
      list.has(blacklist.bloqueados, d.firmante)
    !firmante_bloqueado && list.has(self.extra_signatories, d.firmante)
  }
}

use aiken/interval
use cardano/transaction.{OutputReference, Transaction, find_input}

pub type OracleDatum {
  price: Int
  timestamp: Int
}

pub type SpendDatum {
  oracle_ref: OutputReference
  floor_price: Int
  max_age_ms: Int
}

validator fresh_oracle_price_check {
  fn spend(
    datum: Option<SpendDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(oracle_input) =
      find_input(self.reference_inputs, d.oracle_ref)
    expect InlineDatum(raw) = oracle_input.output.datum
    expect oracle: OracleDatum = raw
    let price_ok = oracle.price >= d.floor_price
    let freshness_ok =
      interval.contains(self.validity_range, oracle.timestamp + d.max_age_ms)
    price_ok && freshness_ok
  }
}

use aiken/collection/list
use cardano/address
use cardano/assets
use cardano/transaction.{OutputReference, Transaction, find_input}

pub type FeedDatum {
  precio: Int
}

pub type DatoGasto {
  feed_ref: OutputReference
  fee_bps: Int
  protocolo_pkh: ByteArray
}

validator fee_proporcional_precio {
  fn spend(
    datum: Option<DatoGasto>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(feed_input) =
      find_input(self.reference_inputs, d.feed_ref)
    expect InlineDatum(raw) = feed_input.output.datum
    expect feed: FeedDatum = raw
    let fee_requerido = feed.precio * d.fee_bps / 10000
    let protocolo_addr = address.from_verification_key(d.protocolo_pkh)
    list.any(
      self.outputs,
      fn(o) {
        o.address == protocolo_addr && assets.lovelace_of(o.value) >= fee_requerido
      },
    )
  }
}
